function computeTotal(itemPrices) {
  let total = 0;
  for (const price of itemPrices) {
    total = total + price;
  }
  return total;
}

function applyDiscount(total, discountPercent) {
  const discount = total * (discountPercent / 100);
  return total - discount;
}

function checkout(itemPrices, discountPercent) {
  const total = computeTotal(itemPrices);
  const finalTotal = applyDiscount(total, discountPercent);
  if (finalTotal < 0) {
    throw new Error("checkout total went negative");
  }
  return finalTotal;
}

module.exports = { computeTotal, applyDiscount, checkout };
